#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

typedef struct {
    char entry[REC_LENGTH];
    float dist;
} neighbor_t;

// Helper function to parse a float from a string segment manually
// This avoids reliance on atof which may not be available or safe in all OpenCL environments
float parse_float(const char *str, int start_offset) {
    const char *s = str + start_offset;
    float result = 0.0f;
    float sign = 1.0f;
    float fraction = 0.0f;
    float divisor = 1.0f;
    int i = 0;
    char c;

    // Skip leading whitespace
    while ((c = s[i]) == ' ' || c == '\t') i++;

    // Check sign
    if (s[i] == '-') {
        sign = -1.0f;
        i++;
    } else if (s[i] == '+') {
        i++;
    }

    // Parse integer part
    while ((c = s[i]) >= '0' && c <= '9') {
        result = result * 10.0f + (c - '0');
        i++;
    }

    // Parse fractional part
    if (c == '.') {
        i++;
        while ((c = s[i]) >= '0' && c <= '9') {
            fraction = fraction * 10.0f + (c - '0');
            divisor *= 10.0f;
            i++;
        }
    }

    return sign * (result + fraction / divisor);
}

__kernel void compute_distances(
    const char *elem_9,
    float *z,
    int x_6,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= x_6) return;

    // Calculate start of the record
    int rec_start = i * REC_LENGTH;

    // Latitude is at LATITUDE_POS - 1 (0-indexed adjustment from original code)
    // Original: rec_iter = elem_9+(i * REC_LENGTH + LATITUDE_POS - 1);
    // The original code assumes the latitude string starts there.
    int lat_offset = rec_start + LATITUDE_POS - 1;

    // Longitude is 5 characters after latitude start in the original logic
    int lon_offset = lat_offset + 5;

    float x_4 = parse_float(elem_9, lat_offset);
    float data_7 = parse_float(elem_9, lon_offset);

    float diff_lat = x_4 - target_lat;
    float diff_long = data_7 - target_long;

    z[i] = sqrt((diff_lat * diff_lat) + (diff_long * diff_long));
}

__kernel void update_neighbors(
    const float *z,
    neighbor_t *val_14,
    const char *elem_9,
    int x_6,
    int k)
{
    int i = get_global_id(0);
    if (i >= x_6) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance (the candidate for replacement)
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (val_14[j].dist > max_dist) {
            max_dist = val_14[j].dist;
            max_idx = j;
        }
    }

    // If the current record is closer than the farthest neighbor found, replace it
    if (current_dist < max_dist) {
        // Copy the record string
        int rec_start = i * REC_LENGTH;
        for (int c = 0; c < REC_LENGTH - 1; c++) {
            val_14[max_idx].entry[c] = elem_9[rec_start + c];
        }
        val_14[max_idx].entry[REC_LENGTH - 1] = '\0';
        val_14[max_idx].dist = current_dist;
    }
}
